class Solution:
    def loudAndRich(self, richer, quiet):
        n = len(quiet)
        # Brute: for each person, BFS over everyone definitely at least as rich.
        # reverse[b] = list of people richer than b
        reverse = {i: [] for i in range(n)}
        for a, b in richer:
            reverse[b].append(a)
        ans = []
        for x in range(n):
            best = x
            stack = [x]
            seen = {x}
            while stack:
                cur = stack.pop()
                if quiet[cur] < quiet[best]:
                    best = cur
                for nxt in reverse[cur]:
                    if nxt not in seen:
                        seen.add(nxt)
                        stack.append(nxt)
            ans.append(best)
        return ans

