class Solution:
    def loudAndRich(self, richer, quiet):
        n = len(quiet)
        graph = {i: [] for i in range(n)}
        for a, b in richer:
            graph[b].append(a)
        ans = [-1] * n
        def dfs(x):
            if ans[x] != -1:
                return ans[x]
            best = x
            for y in graph[x]:
                cand = dfs(y)
                if quiet[cand] < quiet[best]:
                    best = cand
            ans[x] = best
            return best
        for i in range(n):
            dfs(i)
        return ans

